import React, { useState } from 'react';

interface Burger {
  id: number;
  name: string;
  price: string;
  img: string;
}

const burgers: Burger[] = [
  {
    id: 1,
    name: 'Classic Cheeseburger',
    price: '$8.99',
    img: 'https://images.stockcake.com/public/d/f/c/dfc74e17-ba02-49a2-b5b0-d937f6b3017e_large/delicious-cheeseburger-close-up-stockcake.jpg'
  },
  {
    id: 2,
    name: 'Gourmet Burger',
    price: '$11.99',
    img: 'https://media.istockphoto.com/id/924969418/photo/gourmet-hamburger-and-fries.jpg?s=612x612&w=0&k=20&c=1STotLBrTJL7ZnFDhf5vHMcDVZ62Dr4nC1PCAuKJsZQ='
  },
  {
    id: 3,
    name: 'Double Cheeseburger Combo',
    price: '$10.99',
    img: 'https://s7d1.scene7.com/is/image/mcdonaldsstage/DC_202307_8950_EVM_M_2Cheeseburger_Coke_Glass_1564x1564:product-header-mobile?wid=1313&hei=1313&dpr=off'
  }
];

const App: React.FC = () => {
  const [cart, setCart] = useState<Burger[]>([]);

  const addToCart = (burger: Burger) => {
    setCart([...cart, burger]);
  };

  return (
    <div style={styles.appContainer}>
      <header style={styles.heroSection}>
        <img
          src="https://images.stockcake.com/public/d/f/c/dfc74e17-ba02-49a2-b5b0-d937f6b3017e_large/delicious-cheeseburger-close-up-stockcake.jpg"
          alt="Hero Burger"
          style={styles.heroImage}
        />
        <h1 style={styles.heroTitle}>Burger Paradise</h1>
      </header>

      <section style={styles.menuSection}>
        <h2 style={styles.sectionTitle}>Our Menu</h2>
        <div style={styles.cardGrid}>
          {burgers.map((burger) => (
            <div key={burger.id} style={styles.card}>
              <img src={burger.img} alt={burger.name} style={styles.cardImage} />
              <div style={styles.cardBody}>
                <h3 style={styles.cardTitle}>{burger.name}</h3>
                <p style={styles.cardPrice}>{burger.price}</p>
                <button style={styles.button} onClick={() => addToCart(burger)}>
                  Add to Cart
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section style={styles.cartSection}>
        <h2 style={styles.sectionTitle}>Cart ({cart.length})</h2>
        {cart.length === 0 ? (
          <p style={styles.emptyCartText}>Your cart is empty.</p>
        ) : (
          <ul style={styles.cartList}>
            {cart.map((item, index) => (
              <li key={index} style={styles.cartItem}>
                {item.name} - {item.price}
              </li>
            ))}
          </ul>
        )}
      </section>
    </div>
  );
};

